evaluators.evaluation_logic:
const checkpoints = [];

const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');
const cartRaw = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

// Find qualifying SUV full-body color change packages under $2000
const qualifyingPkgs = servicePackages.filter(p => p && p.category === 'full_body_color_change' && Array.isArray(p.vehicle_types) && p.vehicle_types.includes('suv') && typeof p.current_price === 'number' && p.current_price <= 2000);

if (!qualifyingPkgs.length) {
  return 0.0;
}

const minPrice = Math.min(...qualifyingPkgs.map(p => p.current_price));
const cheapestIds = qualifyingPkgs.filter(p => p.current_price === minPrice).map(p => p.id);

// Collect user selections from cart and bookings
let selectedRecords = [];
if (cartRaw && cartRaw.id) {
  const relatedItems = cartItems.filter(ci => ci.cart_id === cartRaw.id);
  selectedRecords = selectedRecords.concat(relatedItems.map(ci => ({
    source: 'cart',
    package_id: ci.package_id,
    vehicle_type: ci.vehicle_type,
    quantity: typeof ci.quantity === 'number' ? ci.quantity : 0
  })));
}
selectedRecords = selectedRecords.concat(bookings.map(b => ({
  source: 'booking',
  package_id: b.package_id,
  vehicle_type: b.vehicle_type,
  quantity: 1
})));

// Selections that match the task criteria (SUV FBCC under $2000)
const qualifyingSelections = selectedRecords.filter(r => {
  const pkg = servicePackages.find(p => p.id === r.package_id);
  return pkg && pkg.category === 'full_body_color_change' && Array.isArray(pkg.vehicle_types) && pkg.vehicle_types.includes('suv') && typeof pkg.current_price === 'number' && pkg.current_price <= 2000 && r.vehicle_type === 'suv';
});

const anyQualifying = qualifyingSelections.length > 0;
checkpoints.push({ passed: anyQualifying, weight: 0.4 });

// Check that at least one selected item is the cheapest qualifying option
const cheapestSelected = qualifyingSelections.some(r => cheapestIds.includes(r.package_id));
checkpoints.push({ passed: cheapestSelected, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');
const slots = JSON.parse(localStorage.getItem('appointment_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');

const baselineDateStr = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const baselineDate = new Date(baselineDateStr + 'T00:00:00Z');

// Custom racing stripes packages that support coupes
const stripesPkgIds = servicePackages
  .filter(p => p && p.category === 'custom_racing_stripes' && Array.isArray(p.vehicle_types) && (p.vehicle_types.includes('coupe') || p.vehicle_types.includes('2_door_coupe')))
  .map(p => p.id);

if (!stripesPkgIds.length) {
  return 0.0;
}

// Identify candidate Saturday morning (9–11 AM) slots for these packages, after baseline date
const candidateSlots = slots.filter(s => {
  if (!s || !s.start_datetime || !stripesPkgIds.includes(s.package_id)) return false;
  const d = new Date(s.start_datetime);
  if (!(d > baselineDate)) return false;
  const day = d.getUTCDay(); // 6 = Saturday
  if (day !== 6) return false;
  const hour = d.getUTCHours();
  const minute = d.getUTCMinutes();
  const minutesSinceMidnight = hour * 60 + minute;
  if (minutesSinceMidnight < 9 * 60 || minutesSinceMidnight > 11 * 60) return false;
  // Treat a slot as effectively available if it is currently available OR was booked by this user
  const bookedForSlot = bookings.some(b => b.package_id === s.package_id && b.location_id === s.location_id && b.appointment_start === s.start_datetime);
  if (!s.is_available && !bookedForSlot) return false;
  return true;
});

if (!candidateSlots.length) {
  return 0.0;
}

candidateSlots.sort((a, b) => new Date(a.start_datetime).getTime() - new Date(b.start_datetime).getTime());
const earliestSlot = candidateSlots[0];

// Find any booking that matches a Saturday 9–11 AM custom racing stripes coupe appointment after baseline
const saturdayMorningBookings = bookings.filter(b => {
  if (!b || !b.appointment_start) return false;
  const pkg = servicePackages.find(p => p.id === b.package_id);
  if (!pkg || pkg.category !== 'custom_racing_stripes') return false;
  if (b.vehicle_type !== 'coupe') return false;
  const d = new Date(b.appointment_start);
  if (!(d > baselineDate)) return false;
  const day = d.getUTCDay();
  if (day !== 6) return false;
  const hour = d.getUTCHours();
  const minute = d.getUTCMinutes();
  const minutesSinceMidnight = hour * 60 + minute;
  if (minutesSinceMidnight < 9 * 60 || minutesSinceMidnight > 11 * 60) return false;
  return true;
});

const hasAnySaturdayMorningBooking = saturdayMorningBookings.length > 0;
checkpoints.push({ passed: hasAnySaturdayMorningBooking, weight: 0.4 });

// Check that the booked slot is the earliest qualifying one and is confirmed
const earliestBooking = bookings.find(b => b.package_id === earliestSlot.package_id && b.location_id === earliestSlot.location_id && b.appointment_start === earliestSlot.start_datetime);
const earliestPkg = earliestBooking ? servicePackages.find(p => p.id === earliestBooking.package_id) : null;
const bookedEarliestCorrect = !!earliestBooking && earliestBooking.status === 'confirmed' && earliestPkg && earliestPkg.category === 'custom_racing_stripes' && earliestBooking.vehicle_type === 'coupe';

checkpoints.push({ passed: bookedEarliestCorrect, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const configs = JSON.parse(localStorage.getItem('paint_configurations') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_configurations') || '[]');

// Qualifying two-tone red/black gloss configs for 2-door coupe under or equal to 1800
const qualifyingConfigs = configs.filter(c => c && c.vehicle_type === '2_door_coupe' && String(c.primary_color || '').toLowerCase() === 'red' && String(c.secondary_color || '').toLowerCase() === 'black' && c.primary_finish === 'gloss' && c.secondary_finish === 'gloss' && !!c.is_two_tone && typeof c.price === 'number' && c.price <= 1800);

if (!qualifyingConfigs.length) {
  return 0.0;
}

const qualifyingIds = qualifyingConfigs.map(c => c.id);
const minPrice = Math.min(...qualifyingConfigs.map(c => c.price));
const cheapestIds = qualifyingConfigs.filter(c => c.price === minPrice).map(c => c.id);

// Saved configurations that meet the criteria
const savedQualifying = saved.filter(s => qualifyingIds.includes(s.configuration_id));
const hasSavedQualifying = savedQualifying.length > 0;
checkpoints.push({ passed: hasSavedQualifying, weight: 0.4 });

// Check that at least one saved configuration is the cheapest qualifying one
const savedCheapest = savedQualifying.some(s => cheapestIds.includes(s.configuration_id));
checkpoints.push({ passed: savedCheapest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const offers = JSON.parse(localStorage.getItem('special_offers') || '[]');
const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');
const cartRaw = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

if (!cartRaw || !cartRaw.id || !Array.isArray(cartRaw.items) || !cartRaw.items.length) {
  return 0.0;
}

const relatedItems = cartItems.filter(ci => ci.cart_id === cartRaw.id);

// Packages in cart that are full-body color change and priced >= 1200
const qualifyingCartItems = relatedItems.filter(ci => {
  const pkg = servicePackages.find(p => p.id === ci.package_id);
  return pkg && pkg.category === 'full_body_color_change' && typeof pkg.current_price === 'number' && pkg.current_price >= 1200;
});

const hasQualifyingCartItem = qualifyingCartItems.length > 0;
const promoApplied = typeof cartRaw.promo_code === 'string' && cartRaw.promo_code.trim().length > 0 && typeof cartRaw.discount_amount === 'number' && cartRaw.discount_amount > 0;

// CP1: cart has a qualifying FBCC item over $1200 AND a promo code with non-zero discount applied
checkpoints.push({ passed: hasQualifyingCartItem && promoApplied, weight: 0.5 });

// Find the offer corresponding to the applied promo code, if any
const appliedCode = cartRaw.promo_code || '';
const matchedOffer = offers.find(o => o && typeof o.promo_code === 'string' && o.promo_code.toLowerCase() === appliedCode.toLowerCase() && o.status === 'active');

let offerAppliesToCart = false;
if (matchedOffer && hasQualifyingCartItem) {
  const packageIdsInCart = qualifyingCartItems.map(ci => ci.package_id);
  const offerPackageIds = Array.isArray(matchedOffer.applicable_package_ids) ? matchedOffer.applicable_package_ids : [];
  const offerCategories = Array.isArray(matchedOffer.applicable_categories) ? matchedOffer.applicable_categories : [];

  const appliesByPackage = offerPackageIds.length ? packageIdsInCart.some(id => offerPackageIds.includes(id)) : false;
  const appliesByCategory = offerCategories.length ? qualifyingCartItems.some(ci => {
    const pkg = servicePackages.find(p => p.id === ci.package_id);
    return pkg && offerCategories.includes(pkg.category);
  }) : false;

  // Check minimum order amount against sum of qualifying item prices
  const subtotalQualifying = qualifyingCartItems.reduce((sum, ci) => {
    const pkg = servicePackages.find(p => p.id === ci.package_id);
    return sum + (pkg && typeof pkg.current_price === 'number' ? pkg.current_price * (ci.quantity || 1) : 0);
  }, 0);

  const minOk = typeof matchedOffer.min_order_amount === 'number' ? subtotalQualifying >= matchedOffer.min_order_amount : true;

  offerAppliesToCart = (appliesByPackage || appliesByCategory || (!offerPackageIds.length && !offerCategories.length)) && minOk;
}

// CP2: the applied promo code corresponds to an active offer that actually applies to at least one qualifying FBCC cart item
checkpoints.push({ passed: !!matchedOffer && offerAppliesToCart, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const servicePackages = JSON.parse(localStorage.getItem('service_packages') || '[]');
const comparisonLists = JSON.parse(localStorage.getItem('comparison_lists') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

const list = comparisonLists[0] || null;
const comparedIds = list && Array.isArray(list.package_ids) ? list.package_ids : [];

// Packages in comparison that are full-body repaint
const comparedRepaints = comparedIds.map(id => servicePackages.find(p => p && p.id === id)).filter(p => p && p.category === 'full_body_repaint');

const hasStandard = comparedRepaints.some(p => p.clear_coat_type === 'standard_clear_coat');
const hasCeramic = comparedRepaints.some(p => p.clear_coat_type === 'ceramic_clear_coat');

// CP1: comparison list includes at least one full-body repaint with standard clear coat AND one with ceramic clear coat
checkpoints.push({ passed: hasStandard && hasCeramic, weight: 0.4 });

// Among all full-body repaint packages, find those with the longest warranty
const allRepaints = servicePackages.filter(p => p && p.category === 'full_body_repaint' && typeof p.warranty_months === 'number');
if (!allRepaints.length) {
  // No repaint packages to compare
  checkpoints.push({ passed: false, weight: 0.6 });
  return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
}

const maxWarranty = Math.max(...allRepaints.map(p => p.warranty_months));
const bestWarrantyIds = allRepaints.filter(p => p.warranty_months === maxWarranty).map(p => p.id);

// Check for a confirmed booking using one of the longest-warranty repaint packages
const bookedBest = bookings.some(b => bestWarrantyIds.includes(b.package_id) && b.status === 'confirmed');

checkpoints.push({ passed: bookedBest, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const openedId = localStorage.getItem('task6_openedLocationDetailsId');
const mapIdRaw = localStorage.getItem('task6_mapOpenedForLocationId');
const mapId = mapIdRaw === 'null' || mapIdRaw === null ? null : mapIdRaw;

// Approximate _findNearestLocationsByZip behavior for ZIP 90001 and radius 20
const targetZip = '90001';
const active = locations.filter(l => l && l.is_active !== false);
let nearest = active.filter(l => String(l.postal_code || '').trim() === targetZip);
if (!nearest.length && targetZip.length >= 3) {
  const prefix = targetZip.slice(0, 3);
  nearest = active.filter(l => String(l.postal_code || '').slice(0, 3) === prefix);
}

if (!nearest.length) {
  return 0.0;
}

// Sort by rating high to low (default 0 if missing)
nearest.sort((a, b) => (b.rating || 0) - (a.rating || 0));
const highest = nearest[0];
const highestId = highest.id;

// User must have opened details for the highest-rated location;
// if they opened a map, it must correspond to the same location.
const openedCorrect = !!openedId && openedId === highestId;
const mapConsistent = !mapId || mapId === highestId;

checkpoints.push({ passed: openedCorrect && mapConsistent, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const inquiries = JSON.parse(localStorage.getItem('contact_inquiries') || '[]');

// Look for an inquiry about fleet/commercial services
const fleetInquiries = inquiries.filter(i => i && i.inquiry_type === 'fleet_commercial');

if (!fleetInquiries.length) {
  return 0.0;
}

// Choose the most recent fleet inquiry (by created_at, if present)
fleetInquiries.sort((a, b) => {
  const ta = a.created_at ? new Date(a.created_at).getTime() : 0;
  const tb = b.created_at ? new Date(b.created_at).getTime() : 0;
  return tb - ta;
});

const inquiry = fleetInquiries[0];
const fleetSize = typeof inquiry.fleet_size === 'number' ? inquiry.fleet_size : null;

// CP1: Fleet/commercial inquiry with fleet_size >= 6
const cp1Passed = fleetSize !== null && fleetSize >= 6;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2: Preferred contact method is phone and a phone number is provided
const cp2Passed = inquiry.preferred_contact_method === 'phone' && typeof inquiry.phone === 'string' && inquiry.phone.trim().length > 0;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3: Message is detailed (>= 50 chars) and mentions 'fleet'
const msg = typeof inquiry.message === 'string' ? inquiry.message : '';
const cp3Passed = msg.length >= 50 && msg.toLowerCase().includes('fleet');
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const galleryItems = JSON.parse(localStorage.getItem('gallery_items') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_gallery_items') || '[]');
let favoritesPageViewed = false;
try {
  const raw = localStorage.getItem('task8_favoritesPageViewed');
  favoritesPageViewed = raw ? JSON.parse(raw) === true : false;
} catch (e) {
  favoritesPageViewed = false;
}

// Determine the first five items that are matte and have black or gray as a dominant color
const matteBlackOrGray = galleryItems.filter(it => it && it.finish_type === 'matte' && Array.isArray(it.dominant_colors) && it.dominant_colors.some(c => c === 'black' || c === 'gray'));
const firstFive = matteBlackOrGray.slice(0, 5).map(it => it.id);

if (!firstFive.length) {
  return 0.0;
}

const favoritedTargetCount = firstFive.filter(id => favorites.some(f => f.gallery_item_id === id)).length;

// CP1: All first five qualifying matte black/gray items are in favorites
checkpoints.push({ passed: favoritedTargetCount >= firstFive.length, weight: 0.7 });

// CP2: Favorites page viewed AND all five correct items are favorited
const cp2Passed = favoritesPageViewed && favoritedTargetCount >= firstFive.length;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
